const texto = $json.output || "";

// 1. Extraer links de Drive
const matches = [...texto.matchAll(/https?:\/\/[^\s)]+/g)];
const links = matches.map(m => m[0]);

const extraerIdDrive = (url) => {
    if (!url) return null;
    const match = url.match(/(?:\/d\/|id=)([a-zA-Z0-9_-]{25,})/);
    return match ? match[1] : null;
};

const convertirDirecto = (id) => {
    if (!id) return null;
    return `https://drive.google.com/uc?export=view&id=${id}`;
};

const id1 = extraerIdDrive(links[0]);
const id2 = extraerIdDrive(links[1]);

// 2. Obtener número del cliente (YCloud)
let remoteJid_final = null;
try {
    remoteJid_final = $node["Webhook"].json.body.whatsappInboundMessage?.from 
                   || $node["Webhook"].json.body.from;
} catch (e) {
    remoteJid_final = null;
}

// Asegurar formato E.164 con +
if (remoteJid_final && !remoteJid_final.startsWith('+')) {
    let onlyDigits = remoteJid_final.replace(/\D/g, '');
    if (onlyDigits.length === 8) onlyDigits = '502' + onlyDigits;
    remoteJid_final = '+' + onlyDigits;
}

return {
    tieneFotos: !!id1,
    foto1: convertirDirecto(id1),
    foto2: convertirDirecto(id2),
    remoteJid_fotos: remoteJid_final
};

