const items = $input.all();
const newItems = [];

for (const item of items) {
    let textoOriginal = (item.json.output || item.json.respuesta_cliente || "").toString();

    const esPedidoFinal = textoOriginal.includes("#PEDIDO_LISTO") || textoOriginal.includes("#PEDIDO_CONFIRMADO");
    const esSoporte = textoOriginal.includes("#SOPORTE");
    const esVenta = textoOriginal.includes("#VENTA");

    const enviarNotificacion = esPedidoFinal || esSoporte || esVenta;

    let textoLimpio = textoOriginal
        .replace(/#PEDIDO_LISTO|#PEDIDO_CONFIRMADO|#VENTA_PROCESO|#VENTA|#BODEGA|#SOPORTE|#REVISAR_TECNICO|#TRANSFERENCIA|#VENTA_ESPECIALIZADA|#FLUJO_NORMAL/gi, "")
        // Quitar links de Google Drive completos (incluso entre paréntesis)
        .replace(/\(?\s*https?:\/\/drive\.google\.com\/[^\s)]+\s*\)?/gi, "")
        // Quitar frases tipo "[Ver foto]" o "[Ver imagen]"
        .replace(/\[Ver foto\]|\[Ver imagen\]|\[ver foto\]|\[ver imagen\]/gi, "")
        // Limpiar dobles espacios y saltos extra
        .replace(/\s+/g, " ")
        .replace(/\s\./g, ".")
        .trim();

    let rawNumber = item.json.remoteJid || 
                    item.json.body?.data?.key?.remoteJid || 
                    item.json.remoteJid_final ||
                    ( ( $node["Webhook"] ) ? ($node["Webhook"].json.body.whatsappInboundMessage?.from || $node["Webhook"].json.body.from) : null );

    let cleanNumber = null;
    if (rawNumber) {
        let onlyDigits = rawNumber.toString().replace(/\D/g, '');
        if (onlyDigits.length === 8) {
            onlyDigits = '502' + onlyDigits;
        }
        cleanNumber = '+' + onlyDigits;
    }

    newItems.push({
        json: {
            ...item.json,
            texto_limpio: textoLimpio,
            remoteJid_final: cleanNumber,
            notificar_vip: enviarNotificacion,
            aviso_ferni: esPedidoFinal ? "🚀 *PEDIDO LISTO*" : 
                         esSoporte ? "🔧 *SOPORTE*" : 
                         esVenta ? "💰 *VENTA*" : "" 
        }
    });
}
return newItems;

const items = $input.all();
const newItems = [];

for (const item of items) {
    let mensajeCliente = "";

    try {
        mensajeCliente = $node["Merge1"].json.mensaje || item.json.mensaje;
    } catch (e) {
        mensajeCliente = item.json.mensaje || "Mensaje no recuperado";
    }

    let respuestaIA = item.json.output || item.json.respuesta_cliente || "";

    newItems.push({
        json: {
            ...item.json,
            resumen_cliente: mensajeCliente, 
            resumen_ia: respuestaIA,
            remoteJid_final: item.json.remoteJid_final || item.json.body?.data?.key?.remoteJid
        }
    });
}

return newItems;

const cache = $('Redis Cache').item.json.bot_status;
const webhookData = $('Webhook').item.json;

// Si Redis ya tiene flag, marcar como apagado
if (cache === 'manual') {
    return [{
        json: {
            ...webhookData,
            bot_apagado: true,
            origen: 'redis_cache'
        }
    }];
}

// Si no, revisar la respuesta de YCloud
const response = $input.item.json;
let contacts = [];

if (Array.isArray(response)) {
    contacts = response;
} else if (response.items) {
    contacts = response.items;
} else if (response.data) {
    contacts = response.data;
}

const contact = contacts[0] || {};
const tags = contact.tags || [];
const customAttrs = contact.customAttributes || {};

const tieneTag = tags.some(t => 
    String(t).toLowerCase() === 'bot_desactivado'
);
const tieneAttr = String(customAttrs.estado_bot || '').toLowerCase() === 'off';

const botApagado = tieneTag || tieneAttr;

return [{
    json: {
        ...webhookData,
        bot_apagado: botApagado,
        origen: botApagado ? 'ycloud' : 'activo',
        debug_tags: tags,
        debug_attrs: customAttrs,
        phoneNumber: webhookData.body.whatsappInboundMessage.from.replace(/\D/g, '')
    }
}];
